const leads = $input.first().json.values || [];
const headers = leads[0] || [];
const today = new Date();
const results = [];

for (let i = 1; i < leads.length; i++) {
  const row = leads[i];
  const status = row[headers.indexOf('status')] || '';
  const lastContact = row[headers.indexOf('last_contact')] || '';
  const daysSince = lastContact ? Math.floor((today - new Date(lastContact)) / 86400000) : 999;

  if (status === 'active' && daysSince >= 3) {
    results.push({
      name: row[headers.indexOf('name')] || '',
      email: row[headers.indexOf('email')] || '',
      service: row[headers.indexOf('service_interest')] || '',
      last_contact: lastContact,
      days_since: daysSince,
      touchpoints: parseInt(row[headers.indexOf('touchpoints')] || '0'),
      row_index: i + 1
    });
  }
}

return results.map(r => ({ json: r }));
